SELECT p.first_name, p.last_name
FROM practitioners p
WHERE p.primary_specialty = 'DIAGNOSTIC RADIOLOGY';

SELECT COUNT(DISTINCT practitioner_id) 
FROM practitioner_employment 
WHERE position = 'Radiologist';

SELECT first_name, last_name
FROM practitioners
WHERE practitioner_id = 0;

SELECT AVG(overall_mips_score) 
FROM practitioners 
WHERE medical_school = 'Ohio State University College of Medicine';

SELECT COUNT(practitioner_id) AS diagnostic_radiology_count
FROM practitioners
WHERE primary_specialty = 'DIAGNOSTIC RADIOLOGY';
